const awsConfig = {
  Auth: {
    Cognito: {
      userPoolId: 'eu-west-2_iAqZXmHqt', // e.g., eu-west-2_xxxxxxxxx
      userPoolClientId: '7652um50ipcd41rj4rce2tb3dd', // e.g., 1a2b3c4d5e6f7g8h9i0j1k2l3m
      loginWith: {
        email: true,
      },
    }
  },
  API: {
    baseUrl: 'YOUR_API_GATEWAY_URL' // e.g., https://xxxxxxxxxx.execute-api.eu-west-2.amazonaws.com
  }
};

export default awsConfig;
